// Implicit flow client in JavaScript for a single-page application

// Parse access token from URL fragment (#access_token=...) after authorization
const accessToken = window.location.hash.split('=').pop();

// Use the token for API calls and store it for the session duration
const apiCall = async () => {
  const response = await fetch(`https://api.example.com/data`, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });
  const data = await response.json();
  console.log(data);
};

// Store the token for the session duration
const storeToken = () => {
  localStorage.setItem('access_token', accessToken);
};

// Retrieve the stored token and use it for API calls
const retrieveToken = () => {
  const storedToken = localStorage.getItem('access_token');
  if (storedToken) {
    apiCall();
  } else {
    console.log('No access token found in storage.');
  }
};